  "{{count}} hook configured": "{{count}} \u4EF6\u306E\u30D5\u30C3\u30AF\u304C\u8A2D\u5B9A\u3055\u308C\u3066\u3044\u307E\u3059",
  "{{count}} hooks configured": "{{count}} \u4EF6\u306E\u30D5\u30C3\u30AF\u304C\u8A2D\u5B9A\u3055\u308C\u3066\u3044\u307E\u3059",
  "This menu is read-only. To add or modify hooks, edit settings.json directly or ask Qwen Code.": "\u3053\u306E\u30E1\u30CB\u30E5\u30FC\u306F\u8AAD\u307F\u53D6\u308A\u5C02\u7528\u3067\u3059\u3002\u30D5\u30C3\u30AF\u3092\u8FFD\u52A0\u307E\u305F\u306F\u5909\u66F4\u3059\u308B\u306B\u306F\u3001settings.json \u3092\u76F4\u63A5\u7DE8\u96C6\u3059\u308B\u304B\u3001Qwen Code \u306B\u5C0B\u306D\u3066\u304F\u3060\u3055\u3044\u3002",
  "Enter to select \xB7 Esc to cancel": "Enter \u3067\u9078\u629E \xB7 Esc \u3067\u30AD\u30E3\u30F3\u30BB\u30EB",
  // Hooks - Detail Step
  "Exit codes:": "\u7D42\u4E86\u30B3\u30FC\u30C9\uFF1A",
  "Configured hooks:": "\u8A2D\u5B9A\u6E08\u307F\u306E\u30D5\u30C3\u30AF\uFF1A",
