  "To add hooks, edit settings.json directly or ask Qwen.": "\u30D5\u30C3\u30AF\u3092\u8FFD\u52A0\u3059\u308B\u306B\u306F\u3001settings.json \u3092\u76F4\u63A5\u7DE8\u96C6\u3059\u308B\u304B\u3001Qwen \u306B\u5C0B\u306D\u3066\u304F\u3060\u3055\u3044\u3002",
  "Enter to select \xB7 Esc to go back": "Enter \u3067\u9078\u629E \xB7 Esc \u3067\u623B\u308B",
