  "Hook details": "\u30D5\u30C3\u30AF\u8A73\u7D30",
  "Event:": "\u30A4\u30D9\u30F3\u30C8\uFF1A",
  "Extension:": "\u62E1\u5F35\u6A5F\u80FD\uFF1A",
  "Desc:": "\u8AAC\u660E\uFF1A",
  "No hook config selected": "\u30D5\u30C3\u30AF\u8A2D\u5B9A\u304C\u9078\u629E\u3055\u308C\u3066\u3044\u307E\u305B\u3093",
  "To modify or remove this hook, edit settings.json directly or ask Qwen to help.": "\u3053\u306E\u30D5\u30C3\u30AF\u3092\u5909\u66F4\u307E\u305F\u306F\u524A\u9664\u3059\u308B\u306B\u306F\u3001settings.json \u3092\u76F4\u63A5\u7DE8\u96C6\u3059\u308B\u304B\u3001Qwen \u306B\u5C0B\u306D\u3066\u304F\u3060\u3055\u3044\u3002",
  // Hooks - Disabled Step
  "Hook Configuration - Disabled": "\u30D5\u30C3\u30AF\u8A2D\u5B9A - \u7121\u52B9",
