  "{{count}} configured hook": "{{count}} \u500B\u306E\u8A2D\u5B9A\u3055\u308C\u305F\u30D5\u30C3\u30AF",
  "{{count}} configured hooks": "{{count}} \u500B\u306E\u8A2D\u5B9A\u3055\u308C\u305F\u30D5\u30C3\u30AF",
  "When hooks are disabled:": "\u30D5\u30C3\u30AF\u304C\u7121\u52B9\u306A\u5834\u5408\uFF1A",
  "No hook commands will execute": "\u30D5\u30C3\u30AF\u30B3\u30DE\u30F3\u30C9\u306F\u5B9F\u884C\u3055\u308C\u307E\u305B\u3093",
  "StatusLine will not be displayed": "StatusLine \u306F\u8868\u793A\u3055\u308C\u307E\u305B\u3093",
  "Tool operations will proceed without hook validation": "\u30C4\u30FC\u30EB\u64CD\u4F5C\u306F\u30D5\u30C3\u30AF\u691C\u8A3C\u306A\u3057\u3067\u7D9A\u884C\u3055\u308C\u307E\u3059",
  'To re-enable hooks, remove "disableAllHooks" from settings.json or ask Qwen Code.': '\u30D5\u30C3\u30AF\u3092\u518D\u6709\u52B9\u5316\u3059\u308B\u306B\u306F\u3001settings.json \u304B\u3089 "disableAllHooks" \u3092\u524A\u9664\u3059\u308B\u304B\u3001Qwen Code \u306B\u5C0B\u306D\u3066\u304F\u3060\u3055\u3044\u3002',
  // Hooks - Source
  Project: "\u30D7\u30ED\u30B8\u30A7\u30AF\u30C8",
  User: "\u30E6\u30FC\u30B6\u30FC",
  Skill: "\u30B9\u30AD\u30EB",
  System: "\u30B7\u30B9\u30C6\u30E0",
