  "User Settings": "\u30E6\u30FC\u30B6\u30FC\u8A2D\u5B9A",
  "System Settings": "\u30B7\u30B9\u30C6\u30E0\u8A2D\u5B9A",
  Extensions: "\u62E1\u5F35\u6A5F\u80FD",
  "Session (temporary)": "\u30BB\u30C3\u30B7\u30E7\u30F3\uFF08\u4E00\u6642\uFF09",
