  "Before tool execution": "\u30C4\u30FC\u30EB\u5B9F\u884C\u524D",
  "After tool execution": "\u30C4\u30FC\u30EB\u5B9F\u884C\u5F8C",
  "After tool execution fails": "\u30C4\u30FC\u30EB\u5B9F\u884C\u5931\u6557\u6642",
  "When notifications are sent": "\u901A\u77E5\u9001\u4FE1\u6642",
  "When the user submits a prompt": "\u30E6\u30FC\u30B6\u30FC\u304C\u30D7\u30ED\u30F3\u30D7\u30C8\u3092\u9001\u4FE1\u3057\u305F\u6642",
  "When a slash command expands into a prompt": "\u30B9\u30E9\u30C3\u30B7\u30E5\u30B3\u30DE\u30F3\u30C9\u304C\u30D7\u30ED\u30F3\u30D7\u30C8\u306B\u5C55\u958B\u3055\u308C\u305F\u6642",
  "When a new session is started": "\u65B0\u3057\u3044\u30BB\u30C3\u30B7\u30E7\u30F3\u304C\u958B\u59CB\u3055\u308C\u305F\u6642",
  "Right before Qwen Code concludes its response": "Qwen Code \u304C\u5FDC\u7B54\u3092\u7D42\u4E86\u3059\u308B\u76F4\u524D",
  "When a subagent (Agent tool call) is started": "\u30B5\u30D6\u30A8\u30FC\u30B8\u30A7\u30F3\u30C8\uFF08Agent \u30C4\u30FC\u30EB\u547C\u3073\u51FA\u3057\uFF09\u304C\u958B\u59CB\u3055\u308C\u305F\u6642",
  "Right before a subagent concludes its response": "\u30B5\u30D6\u30A8\u30FC\u30B8\u30A7\u30F3\u30C8\u304C\u5FDC\u7B54\u3092\u7D42\u4E86\u3059\u308B\u76F4\u524D",
  "Before conversation compaction": "\u4F1A\u8A71\u5727\u7E2E\u524D",
  "When a session is ending": "\u30BB\u30C3\u30B7\u30E7\u30F3\u7D42\u4E86\u6642",
  "When a permission dialog is displayed": "\u6A29\u9650\u30C0\u30A4\u30A2\u30ED\u30B0\u8868\u793A\u6642",
  "When a new todo item is created": "\u65B0Todo\u9805\u76EE\u4F5C\u6210\u6642",
  "When a todo item is marked as completed": "Todo\u9805\u76EE\u5B8C\u4E86\u6642",
  // Hooks - Event Descriptions (detailed)
  "Input to command is JSON of tool call arguments.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F\u30C4\u30FC\u30EB\u547C\u3073\u51FA\u3057\u5F15\u6570\u306E JSON \u3067\u3059\u3002",
  'Input to command is JSON with fields "inputs" (tool call arguments) and "response" (tool call response).': '\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F "inputs"\uFF08\u30C4\u30FC\u30EB\u547C\u3073\u51FA\u3057\u5F15\u6570\uFF09\u3068 "response"\uFF08\u30C4\u30FC\u30EB\u547C\u3073\u51FA\u3057\u5FDC\u7B54\uFF09\u30D5\u30A3\u30FC\u30EB\u30C9\u3092\u6301\u3064 JSON \u3067\u3059\u3002',
  "Input to command is JSON with tool_name, tool_input, tool_use_id, error, error_type, is_interrupt, and is_timeout.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F tool_name\u3001tool_input\u3001tool_use_id\u3001error\u3001error_type\u3001is_interrupt\u3001is_timeout \u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with notification message and type.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F\u901A\u77E5\u30E1\u30C3\u30BB\u30FC\u30B8\u3068\u30BF\u30A4\u30D7\u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with original user prompt text.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F\u5143\u306E\u30E6\u30FC\u30B6\u30FC\u30D7\u30ED\u30F3\u30D7\u30C8\u30C6\u30AD\u30B9\u30C8\u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with command_name, command_args, and expanded prompt text.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F command_name\u3001command_args\u3001\u5C55\u958B\u5F8C\u306E\u30D7\u30ED\u30F3\u30D7\u30C8\u30C6\u30AD\u30B9\u30C8\u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with session start source.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F\u30BB\u30C3\u30B7\u30E7\u30F3\u958B\u59CB\u30BD\u30FC\u30B9\u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with session end reason.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F\u30BB\u30C3\u30B7\u30E7\u30F3\u7D42\u4E86\u7406\u7531\u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with agent_id and agent_type.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F agent_id \u3068 agent_type \u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with agent_id, agent_type, and agent_transcript_path.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F agent_id\u3001agent_type\u3001agent_transcript_path \u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with compaction details.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F\u5727\u7E2E\u8A73\u7D30\u3092\u6301\u3064 JSON \u3067\u3059\u3002",
  "Input to command is JSON with tool_name, tool_input, and tool_use_id. Output JSON with hookSpecificOutput containing decision to allow or deny.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F tool_name\u3001tool_input\u3001tool_use_id \u3092\u6301\u3064 JSON \u3067\u3059\u3002\u8A31\u53EF\u307E\u305F\u306F\u62D2\u5426\u306E\u6C7A\u5B9A\u3092\u542B\u3080 hookSpecificOutput \u3092\u6301\u3064 JSON \u3092\u51FA\u529B\u3057\u307E\u3059\u3002",
  "Input to command is JSON with todo_id, todo_content, todo_status, all_todos, and phase. In validation, output JSON with decision (allow/block/deny) and reason. In postWrite, block/deny is ignored.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F todo_id\u3001todo_content\u3001todo_status\u3001all_todos\u3001phase \u3092\u6301\u3064 JSON \u3067\u3059\u3002validation \u3067\u306F decision\uFF08allow/block/deny\uFF09\u3068 reason \u3092\u6301\u3064 JSON \u3092\u51FA\u529B\u3057\u307E\u3059\u3002postWrite \u3067\u306F block/deny \u306F\u7121\u8996\u3055\u308C\u307E\u3059\u3002",
  "Input to command is JSON with todo_id, todo_content, previous_status, all_todos, and phase. In validation, output JSON with decision (allow/block/deny) and reason. In postWrite, block/deny is ignored.": "\u30B3\u30DE\u30F3\u30C9\u3078\u306E\u5165\u529B\u306F todo_id\u3001todo_content\u3001previous_status\u3001all_todos\u3001phase \u3092\u6301\u3064 JSON \u3067\u3059\u3002validation \u3067\u306F decision\uFF08allow/block/deny\uFF09\u3068 reason \u3092\u6301\u3064 JSON \u3092\u51FA\u529B\u3057\u307E\u3059\u3002postWrite \u3067\u306F block/deny \u306F\u7121\u8996\u3055\u308C\u307E\u3059\u3002",
  // Hooks - Exit Code Descriptions
