  "Invalid scope: {{scope}}. Please use one of {{scopes}}.": "\u7121\u52B9\u306A\u30B9\u30B3\u30FC\u30D7\u3067\u3059: {{scope}}\u3002{{scopes}} \u306E\u3044\u305A\u308C\u304B\u3092\u6307\u5B9A\u3057\u3066\u304F\u3060\u3055\u3044\u3002",
