  'Extension "{{name}}" successfully disabled for scope "{{scope}}".': '\u30B9\u30B3\u30FC\u30D7 "{{scope}}" \u3067\u62E1\u5F35\u6A5F\u80FD "{{name}}" \u3092\u6B63\u5E38\u306B\u7121\u52B9\u5316\u3057\u307E\u3057\u305F\u3002',
